class Solution:
    def pairSum(self, head):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        n = len(vals)
        best = 0
        for i in range(n // 2):
            best = max(best, vals[i] + vals[n - 1 - i])
        return best

